active.query:
#graphql
      mutation GiftCardCreate($input: GiftCardCreateInput!) {
        giftCardCreate(input: $input) {
          giftCard {
            id
            enabled
            expiresOn
            balance {
              amount
              currencyCode
            }
          }
          userErrors {
            field
            code
            message
          }
        }
      }

